urn stats }                let awayTeam = teams[0]        let homeTeam = teams[1]                if let awayStats = awayTeam["statistics"] as? [[String: Any]],           let homeStats = homeTeam["statistics"] as? [[String: Any]] {                        let desiredStats = getDesiredStats(for: sport)            for statName in desiredStats {                if let awayStat = findStat(named: statName, in: awayStats),                   let homeStat = findStat(named: statName, in: homeStats) {                    stats.append(GameStatistic(                        name: formatStatName(statName),                        awayValue: awayStat,                        homeValue: homeStat                    ))                }            }        }                // Try player stats if team stats empty        if stats.isEmpty, let players = boxscore["players"] as? [[String: Any]] {            stats = parsePlayerStats(players: players, sport: sport)        }                return stats    }        private func getDesiredStats(for sport: SportEndpoint) -> [String] {        switch sport {        case .nba: return ["fieldGoalPct", "threePointFieldGoalPct", "freeThrowPct", "totalRebounds", "assists", "steals", "blocks", "turnovers"]        case .nfl: return ["totalYards", "passingYards", "rushingYards", "firstDowns", "turnovers", "possession"]        case .mlb: return ["hits", "runs", "errors", "leftOnBase"]        case .nhl: return ["shots", "powerPlayGoals", "penaltyMinutes", "faceoffsWon"]        }    }        private func findStat(named name: String, in stats: [[String: Any]]) -> String? {        for stat in stats {            if let statName = stat["name"] as? String, statName.lowercased() == name.lowercased() {                return stat["displayValue"] as? String            }            if let label = stat["label"] as? String, label.lowercased().contains(name.lowercased()) {                return stat["displayValue"] as? String            }        }        return nil    }        private func formatStatName(_ name: String) -> String {        let formatted = name.replacingOccurrences(of: "([a-z])([A-Z])", with: "$1 $2", options: .regularExpression)        return formatted.capitalized            .replacingOccurrences(of: "Pct", with: "%")            .replacingOccurrences(of: "Field Goal", with: "FG")            .replacingOccurrences(of: "Three Point", with: "3PT")            .replacingOccurrences(of: "Free Throw", with: "FT")    }        private func parsePlayerStats(players: [[String: Any]], sport: SportEndpoint) -> [GameStatistic] {        var stats: [GameStatistic] = []        guard players.count >= 2 else { return stats }                let awayPlayers = players[0]        let homePlayers = players[1]                if let awayStatistics = awayPlayers["statistics"] as? [[String: Any]],           let homeStatistics = homePlayers["statistics"] as? [[String: Any]] {                        for i in 0..<min(awayStatistics.count, homeStatistics.count) {                if let awayTotals = awayStatistics[i]["totals"] as? [String],                   let homeTotals = homeStatistics[i]["totals"] as? [String],                   let labels = awayStatistics[i]["labels"] as? [String] {                                        let indices = getStatIndices(for: sport, labels: labels)                    for (name, index) in indices {                        if index < awayTotals.count && index < homeTotals.count {                            stats.append(GameStatistic(name: name, awayValue: awayTotals[index], homeValue: homeTotals[index]))                        }                    }                    break                }            }        }        return stats    }        private func getStatIndices(for sport: SportEndpoint, labels: [String]) -> [(String, Int)] {        var indices: [(String, Int)] = []        let desiredLabels: [String: String]                switch sport {        case .nba: desiredLabels = ["FG%": "FG %", "3P%": "3PT %", "FT%": "FT %", "REB": "Rebounds", "AST": "Assists", "STL": "Steals", "BLK": "Blocks", "TO": "Turnovers", "PTS": "Points"]        case .nfl: desiredLabels = ["YDS": "Total Yards", "PASS": "Passing", "RUSH": "Rushing"]        case .mlb: desiredLabels = ["H": "Hits", "R": "Runs", "E": "Errors", "HR": "Home Runs"]        case .nhl: desiredLabels = ["SOG": "Shots", "PPG": "Power Play", "PIM": "Penalties"]        }                for (i, label) in labels.enumerated() {            if let displayName = desiredLabels[label] {                indices.append((displayName, i))            }        }        return indices    }        // Fetch Standings        func fetchStandings(for sport: SportEndpoint) async throws -> (entries: [StandingEntry], conferences: [ConferenceStandings]) {        let urlString = "https://site.web.api.espn.com/apis/v2/sports/\(sport.rawValue)/standings"        guard let url = URL(string: urlString) else { throw APIError.invalidURL }                let (data, response) = try await URLSession.shared.data(from: url)        guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {            throw APIError.noData        }                guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {            throw APIError.decodingError        }                return parseStandings(json: json)    }        private func parseStandings(json: [String: Any]) -> (entries: [StandingEntry], conferences: [ConferenceStandings]) {        var conferences: [ConferenceStandings] = []        var allEntries: [StandingEntry] = []                if let children = json["children"] as? [[String: Any]] {            for child in children {                let conferenceName = child["name"] as? String ?? "Conference"                var conferenceEntries: [StandingEntry] = []                                // Check for divisions within conference                if let divisions = child["children"] as? [[String: Any]] {                    for division in divisions {                        if let standings = division["standings"] as? [String: Any],                           let entries = standings["entries"] as? [[String: Any]] {                            conferenceEntries.append(contentsOf: parseEntries(entries))                        }                    }                } else if let standings = child["standings"] as? [String: Any],                          let entries = standings["entries"] as? [[String: Any]] {                    conferenceEntries = parseEntries(entries)                }                                // Sort by wins then win percentage                conferenceEntries.sort { $0.wins != $1.wins ? $0.wins > $1.wins : $0.winPercentage > $1.winPercentage }                                if !conferenceEntries.isEmpty {                    conferences.append(ConferenceStandings(name: conferenceName, entries: conferenceEntries))                    allEntries.append(contentsOf: conferenceEntries)                }            }        }                return (allEntries, conferences)    }        private func parseEntries(_ entries: [[String: Any]]) -> [StandingEntry] {        var result: [StandingEntry] = []                for entry in entries {            guard let team = entry["team"] as? [String: Any] else { continue }                        let teamId: String            if let id = team["id"] as? String { teamId = id }            else if let id = team["id"] as? Int { teamId = String(id) }            else { continue }                        let displayName = team["displayName"] as? String ?? ""                        // Handle logo URL (string or array)            var logoURL: String? = nil            if let logo = team["logo"] as? String {                logoURL = logo            } else if let logos = team["logos"] as? [[String: Any]], let firstLogo = logos.first {                logoURL = firstLogo["href"] as? String            }                        let teamInfo = TeamInfo(                id: teamId,                name: team["name"] as? String ?? "",                displayName: displayName,                shortDisplayName: team["shortDisplayName"] as? String ?? displayName,                abbreviation: team["abbreviation"] as? String ?? "",                logo: logoURL,                color: team["color"] as? String,                alternateColor: team["alternateColor"] as? String            )                        var stats: [Stat] = []            if let statsArray = entry["stats"] as? [[String: Any]] {                for stat in statsArray {                    if let name = stat["name"] as? String {                        let value = stat["value"] as? Double ?? 0                        stats.append(Stat(                            name: name,                            displayName: stat["displayName"] as? String ?? name,                            shortDisplayName: stat["shortDisplayName"] as? String,                            description: stat["description"] as? String,                            abbreviation: stat["abbreviation"] as? String,                            value: value,                            displayValue: stat["displayValue"] as? String ?? "\(value)"                        ))                    }                }            }                        result.append(StandingEntry(team: teamInfo, stats: stats))        }        return result    }}enum APIError: Error, LocalizedError {    case invalidURL, noData, decodingError        var errorDescription: String? {        switch self {        case .invalidURL: return "Invalid URL"        case .noData: return "No data received"        case .decodingError: return "Failed to decode response"        }    }}